+import { $internal } from '../common';
+import { isRelation } from '../relation/utils/is-relation';
+import type { Schema } from '../storage';
+import type { Trait } from './types';
+
+export const $aspect = Symbol('aspect');
+
+export type Aspect<T extends readonly Trait[] = readonly Trait[]> = {
+    readonly id: number;
+    readonly traits: T;
+    readonly schema: Schema;
+    readonly [$aspect]: true;
+};
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+/** Creates a single logical view over two or more non-relation traits. */
+export function createAspect<T extends readonly Trait[]>(...inputs: T): Aspect<T> {
+    const traits: Trait[] = [];
+    const fields = new Set<string>();
+
+    for (const input of inputs) {
+        const nested = isAspect(input) ? input.traits : [input];
+        for (const trait of nested) {
+            if (isRelation(trait) || trait[$internal].relation) {
+                throw new Error('Koota: Relations cannot be constituents of an aspect.');
+            }
+            if (traits.includes(trait)) continue;
+            for (const field of Object.keys(trait.schema)) {
+                if (fields.has(field)) {
+                    throw new Error(`Koota: Aspect traits cannot share the field "${field}".`);
+                }
+                fields.add(field);
+            }
+            traits.push(trait);
+        }
+    }
+
+    if (traits.length < 2) throw new Error('Koota: An aspect requires at least two traits.');
+
+    return Object.freeze({
+        [$aspect]: true as const,
+        id: aspectId++,
+        traits: Object.freeze(traits) as unknown as T,
+        schema: Object.freeze(Object.assign({}, ...traits.map((trait) => trait.schema))),
+    });
+}
