+type StateGroup = number[];
+
+function getStateGroups(params: QueryParameter[]): StateGroup[] {
+    const groups: StateGroup[] = [];
+    let index = 0;
+    const add = (input: any) => {
+        if (isAspect(input)) {
+            const group: number[] = [];
+            for (const trait of input.traits) if (trait[$internal].type !== 'tag') group.push(index++);
+            groups.push(group);
+        } else if (input[$internal]?.type !== 'tag') groups.push([index++]);
+    };
+    for (const param of params) {
+        if (isRelationPair(param)) add(param[$internal].relation[$internal].trait);
+        else if (isModifier(param)) {
+            if (param.type === 'not') continue;
+            for (const component of param.components ?? param.traits) add(component);
+        } else add(param);
+    }
+    return groups;
+}
+
+function formatState(state: any[], groups: StateGroup[]): any[] {
+    return groups.map((group) =>
+        group.length === 0 ? {} : group.length === 1 ? state[group[0]] : Object.assign({}, ...group.map((index) => state[index]))
+    );
+}
+
+function distributeState(output: any[], state: any[], groups: StateGroup[]) {
+    for (let i = 0; i < groups.length; i++) {
